        }

        const existingToken = localStorage.getItem("access_token");
        if (!existingToken) {
            router.replace("/auth/signin");
        }
    }, [router, searchParams]);

    return null; // Placeholder return to avoid syntax errors.
}

export default function ReviewsPage() {
    const [isDropdownOpen, setIsDropdownOpen] = useState(false);
    const [sortOption, setSortOption] = useState("Most Recent");

    const reviews = [
        {
            id: 1,
            name: 'Sarah Miller',
            avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sarah',
            time: '2 hours ago',
            task: 'Deliver Birthday Cake',
            rating: 5,
            comment: 'Tver ka doj ach.',
            helpfulCount: 12,
        },
        {
            id: 2,
            name: 'Jason Davis',
            avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Jason',
            time: 'Yesterday',
            task: 'Assemble IKEA Desk',
            rating: 4,
            comment: 'Very professional and punctual. The desk was assembled perfectly in under an hour. Only docked one star because he arrived 5 minutes late, but otherwise a flawless experience.',
            helpfulCount: 3,
        },
    ];

    const RatingBar = ({ label, percentage }: { label: string; percentage: number }) => (
        <div className="flex items-center gap-4 text-sm">
            <span className="w-12 text-slate-500 font-medium">{label}</span>
            <div className="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">
                <div
                    className="h-full bg-[#005bc4] rounded-full"
                    style={{ width: `${percentage}%` }}
                />
            </div>
            <span className="w-8 text-right text-slate-400 font-bold">{percentage}%</span>
        </div>
    );

    const toggleDropdown = () => {
        setIsDropdownOpen(!isDropdownOpen);
    };

    const handleSortOptionClick = (option: string) => {
        setSortOption(option);
        setIsDropdownOpen(false);
    };

    return (
        <div className="min-h-screen bg-white p-8">

            {/* Header Section */}
            <div className="max-w-6xl mx-auto mb-10 flex justify-between items-end">
                <div>
                    <h1 className="text-5xl font-bold text-black tracking-tight mb-2">Community Trust</h1>
                    <p className="text-slate-500 text-lg max-w-md">
                        Browse authentic feedback from your recent clients and see how you're performing across the marketplace.
                    </p>
                </div>

            </div>

            <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-[320px_1fr] gap-8">

                {/* LEFT: Stats Sidebar */}
                <div className="bg-white rounded-4xl p-8 h-fit shadow-xl">
                    <div className="mb-6">
                        <div className="flex items-baseline gap-2 mb-2">
                            <span className="text-6xl font-black text-[#005bc4]">4.9</span>
                            <span className="text-2xl font-bold text-slate-300">/5</span>
                        </div>
                        <div className="flex gap-1 text-orange-500 mb-2">
                            {[...Array(5)].map((_, i) => <Star key={i} size={20} fill="currentColor" />)}
                        </div>
                        <p className="text-slate-400 text-sm font-semibold uppercase tracking-wider">Based on 142 total reviews</p>
                    </div>

                    <div className="space-y-4">
                        <RatingBar label="5 Star" percentage={88} />
                        <RatingBar label="4 Star" percentage={10} />
                        <RatingBar label="3 Star" percentage={2} />
                        <RatingBar label="2 Star" percentage={0} />
                        <RatingBar label="1 Star" percentage={0} />
                    </div>
                </div>


                {/* RIGHT: Feed */}
                <div className="space-y-6">

                    {/* Sort Bar */}
                    <div className="bg-white rounded-2xl p-4 flex items-center gap-4 shadow-sm relative">
                        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-2">Sort By</span>
                        <button
                            className="flex items-center gap-2 bg-slate-100 px-4 py-2 rounded-xl text-sm font-bold text-slate-700"
                            onClick={toggleDropdown}
                        >
                            {sortOption} <ChevronDown size={16} />
                        </button>
                        {isDropdownOpen && (
                            <div className="absolute top-full left-0 mt-2 bg-white rounded-xl shadow-lg w-48">
                                <ul className="py-2">
                                    {[
                                        "Most Recent",
                                        "Highest Rated",
                                        "Lowest Rated",
                                    ].map((option) => (
                                        <li
                                            key={option}
                                            className="px-4 py-2 hover:bg-slate-100 cursor-pointer text-sm text-slate-700"
                                            onClick={() => handleSortOptionClick(option)}
                                        >
                                            {option}
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        )}
                    </div>

                    {/* Review Cards */}
                    {reviews.map((review) => (
                        <div key={review.id} className="bg-white rounded-3xl p-8 shadow-sm border border-slate-50 transition-transform hover:scale-[1.01]">
                            <div className="flex justify-between items-start mb-6">
                                <div className="flex gap-4">
                                    <div className="w-14 h-14 rounded-full bg-slate-100 overflow-hidden">
                                        <img src={review.avatar} alt={review.name} />
                                    </div>
                                    <div>
                                        <h3 className="font-bold text-slate-900 text-lg leading-tight">{review.name}</h3>
                                        <p className="text-sm text-slate-400 font-medium">
                                            {review.time} • <span className="text-[#005bc4] hover:underline cursor-pointer">{review.task}</span>
                                        </p>
                                    </div>
                                </div>
                                <div className="flex gap-0.5 text-orange-500">
                                    {[...Array(5)].map((_, i) => (
                                        <Star
                                            key={i}
                                            size={18}
                                            fill={i < review.rating ? "currentColor" : "none"}
                                            className={i < review.rating ? "" : "text-slate-200"}
                                        />
                                    ))}
                                </div>
                            </div>

                            <p className="text-slate-600 text-lg leading-relaxed mb-8">
                                {review.comment}
                            </p>

                            <div className="flex items-center gap-6 pt-6 border-t border-slate-50">
                                <button className="flex items-center gap-2 text-slate-400 hover:text-[#005bc4] transition-colors text-sm font-bold">
                                    <ThumbsUp size={18} /> Helpful ({review.helpfulCount})
                                </button>
                                <button className="flex items-center gap-2 text-slate-400 hover:text-slate-600 transition-colors text-sm font-bold">
                                    <Reply size={18} /> Reply
                                </button>
                            </div>
                        </div>
                    ))}

                    {/* Load More */}
                    <div className="flex justify-center pt-8">

                        <button className="px-10 py-4 rounded-full border-2 border-slate-400 text-blue-800 font-bold hover:bg-blue-500 hover:text-white hover:border-blue-500 transition-all">
                            Load More Feedback
                        </button>
                    </div>

                </div>

            </div>

        </div>
    );
}

"use client";
import React, { useEffect, useState } from "react";
import Image from "next/image";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useRouter } from "next/router";

export default function Navbar() {
  const pathname = usePathname();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Close mobile menu after route changes.
  useEffect(() => {
    setIsMobileMenuOpen(false);
  }, [pathname]);

  // Define your links
  const links = [
    { name: "Home", href: "/" },
    { name: "About Us", href: "/aboutUs" },
    { name: "Contact Us", href: "/contactUs" },
    { name: "Blog", href: "/blog" },
  ];

  return (
    <header className="sticky top-0 z-50 w-full bg-white border-b border-slate-200/70">
      <nav className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="flex h-16 sm:h-18 md:h-20 items-center justify-between">
          {/* LEFT: Logo + Desktop Nav */}
          <div className="flex items-center gap-2 sm:gap-4 md:gap-8 lg:gap-12 flex-1 min-w-0">

            {/* Logo */}
            <Link href="/" aria-label="Home" className="shrink-0 inline-block">
              <Image
                src="/images/logo.png"
                alt="Jomnus"
                width={100}
                height={32}
                className="w-14 sm:w-18 md:w-24 lg:w-28 object-contain"
                style={{ height: "auto" }}
                priority
              />
            </Link>

            {/* Desktop Navigation */}
            <div className="hidden lg:flex items-center gap-1">
              {links.map((link) => {
                const isActive = pathname === link.href;
                return (
                  <Link
                    key={link.name}
                    href={link.href}
                    className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                      isActive
                        ? "bg-blue-50/80 text-blue-600"
                        : "text-slate-600 hover:text-slate-900 hover:bg-slate-50"
                    }`}
                  >
                    {link.name}
                  </Link>
                );
              })}
            </div>
          </div>

          {/* RIGHT: Auth Buttons (Desktop) + Mobile Menu Button */}
          <div className="flex items-center gap-2 sm:gap-3 flex-shrink-0">
            {/* Desktop Auth Buttons */}
            <div className="hidden md:flex items-center gap-2 sm:gap-3">
              <a
                href="/auth/signin"
                className="px-4 lg:px-5 py-2 text-slate-700 text-sm font-medium rounded-lg hover:bg-slate-100 transition-colors"
              >
                Log In
              </a>
              <a
                href="/auth/register"
                className="px-4 lg:px-5 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
              >
                Sign Up
              </a>
            </div>

            {/* Mobile Menu Button */}
            <button
              type="button"
              className="md:hidden p-2 hover:bg-slate-100 rounded-lg transition text-slate-600"
              aria-label={isMobileMenuOpen ? "Close menu" : "Open menu"}
              aria-expanded={isMobileMenuOpen}
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            >
              <svg
                className="w-5 h-5"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                {isMobileMenuOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMobileMenuOpen && (
          <div className="md:hidden border-t border-slate-200/70 py-4 space-y-3 bg-slate-50/50">
            {/* Mobile Navigation */}
            <div className="space-y-1">
              {links.map((link) => {
                const isActive = pathname === link.href;
                return (
                  <Link
                    key={link.name}
                    href={link.href}
                    onClick={() => setIsMobileMenuOpen(false)}
                    className={`block px-4 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                      isActive
                        ? "bg-blue-50 text-blue-600 font-semibold"
                        : "text-slate-700 hover:bg-white hover:text-slate-900"
                    }`}
                  >
                    {link.name}
                  </Link>
                );
              })}
            </div>

            {/* Mobile Auth Buttons */}
            <div className="grid grid-cols-2 gap-3 pt-2 border-t border-slate-200/70">
              <a
                href="/auth/signin"
                className="px-4 py-2.5 text-center text-sm font-medium text-slate-700 border border-slate-300 rounded-lg hover:bg-slate-100 transition-colors"
              >
                Log In
              </a>
              <a
                href="/auth/register"
                className="px-4 py-2.5 text-center text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors"
              >
                Sign Up
              </a>
            </div>
          </div>
        )}
      </nav>
    </header>
  );
}

